/**
 * Resolve the effective relayPrompt when multiple events may have different values.
 * Strategy: If all events have the same relayPrompt, use it. Otherwise, use default (undefined).
 */
function resolveEffectiveRelayPrompt(events: CronEventWithRelayPrompt[]): string | null | undefined {
  if (events.length === 0) {
    return undefined;
  }

  // Get unique relayPrompt values (normalize undefined to a sentinel for comparison)
  const SENTINEL = Symbol("undefined");
  const relayPrompts = events.map((e) => (e.relayPrompt === undefined ? SENTINEL : e.relayPrompt));

  const uniquePrompts = [...new Set(relayPrompts)];

  // If all events have the same relayPrompt, use it
  if (uniquePrompts.length === 1) {
    return events[0].relayPrompt;
  }

  // Mixed relayPrompt values: use default behavior (relay to user)
  // This ensures consistency and avoids confusing behavior
  return undefined;
}

